const input = $('Execute Workflow Trigger').first().json;
const html = input?.html;
const fileName = input?.fileName || 'document.pdf';

if (!html || (typeof html === 'string' && !html.trim())) {
  return [{ json: { success: false, data: null, error: 'Missing input.html' } }];
}

return [{
  json: { html: typeof html === 'string' ? html : String(html), fileName }
}];

const prepNode = $('Prep for PDF').first().json;
const fileName = prepNode?.fileName || 'document.pdf';
const item = $input.first();

if (item.json?.error || item.json?.message) {
  return [{
    json: {
      success: false,
      data: null,
      error: `PDF generation failed: ${item.json.message || JSON.stringify(item.json.error)}`
    }
  }];
}

const binKeys = item.binary && Object.keys(item.binary);
const binaryProperty = binKeys?.length ? binKeys[0] : null;

if (!binaryProperty) {
  return [{
    json: {
      success: false,
      data: null,
      error: 'PDF service did not return a PDF file'
    }
  }];
}

const pdfBuffer = await this.helpers.getBinaryDataBuffer(0, binaryProperty);
const base64Pdf = pdfBuffer.toString('base64');

if (!base64Pdf) {
  return [{
    json: {
      success: false,
      data: null,
      error: 'PDF service returned empty binary data'
    }
  }];
}

return [{
  json: {
    success: true,
    data: {
      pdfBase64: base64Pdf,
      fileName,
      mimeType: 'application/pdf'
    },
    error: null
  },
  binary: {
    data: {
      data: base64Pdf,
      mimeType: 'application/pdf',
      fileName,
      fileExtension: 'pdf'
    }
  }
}];
